tasks.college_inventory_unique:
function evaluate(input: { item: string }, state: { inventory: string[] }): number {
  if (!state.inventory.includes(input.item)) {
    state.inventory.push(input.item);
  }
  return state.inventory.length;
}

tasks.college_quest_flags:
function evaluate(input: { required: string[]; reward: string }, state: { flags: string[]; rewards: string[] }): boolean {
  const hasRequirements = input.required.every((flag) => state.flags.includes(flag));
  if (!hasRequirements) return false;
  if (!state.rewards.includes(input.reward)) {
    state.rewards.push(input.reward);
  }
  return true;
}

tasks.college_weighted_choice:
function evaluate(input: { options: Array<{ id: string; weight: number }>; roll: number }, state: unknown): string | null {
  let total = 0;
  for (const option of input.options) {
    total += option.weight;
    if (input.roll < total) return option.id;
  }
  return input.options.length ? input.options[input.options.length - 1].id : null;
}

tasks.college_off_by_one_last_index:
function evaluate(input: { items: string[] }, state: unknown): string | null {
  if (input.items.length === 0) return null;
  return input.items[input.items.length - 1];
}

tasks.college_copy_vs_mutation:
function evaluate(input: { values: number[] }, state: unknown): number {
  return input.values.reduce((total, value) => total + value, 0);
}
